85	// ── Pure helpers ──────────────────────────────────────────────────────
86	
87	function updateThread(
88	  threads: Thread[],
89	  threadId: ThreadId,
90	  updater: (t: Thread) => Thread,
91	): Thread[] {
92	  let changed = false;
93	  const next = threads.map((t) => {
94	    if (t.id !== threadId) return t;
95	    const updated = updater(t);
96	    if (updated !== t) changed = true;
97	    return updated;
98	  });
99	  return changed ? next : threads;
100	}
101	
102	function mapProjectsFromReadModel(
103	  incoming: OrchestrationReadModel["projects"],
104	  previous: Project[],
105	): Project[] {
106	  return incoming.map((project) => {
107	    const existing =
108	      previous.find((entry) => entry.id === project.id) ??
109	      previous.find((entry) => entry.cwd === project.workspaceRoot);
110	    return {
111	      id: project.id,
112	      name: project.title,
113	      cwd: project.workspaceRoot,
114	      model:
115	        existing?.model ??
116	        resolveModelSlug(project.defaultModel ?? DEFAULT_MODEL_BY_PROVIDER.codex),
117	      expanded:
118	        existing?.expanded ??
119	        (persistedExpandedProjectCwds.size > 0
120	          ? persistedExpandedProjectCwds.has(project.workspaceRoot)
121	          : true),
122	      scripts: project.scripts.map((script) => ({ ...script })),
123	    };
124	  });
125	}
126	
127	function toLegacySessionStatus(
128	  status: OrchestrationSessionStatus,
129	): "connecting" | "ready" | "running" | "error" | "closed" {
130	  switch (status) {
131	    case "starting":
132	      return "connecting";
133	    case "running":
134	      return "running";
135	    case "error":
136	      return "error";
137	    case "ready":
138	    case "interrupted":
139	      return "ready";
140	    case "idle":
141	    case "stopped":
142	      return "closed";
143	  }
144	}
145	
146	function toLegacyProvider(providerName: string | null): ProviderKind {
147	  if (providerName === "codex") {
148	    return providerName;
149	  }
150	  return "codex";
151	}
152	
153	const CODEX_MODEL_SLUGS = new Set<string>(getModelOptions("codex").map((option) => option.slug));
154	
155	function inferProviderForThreadModel(input: {
156	  readonly model: string;
157	  readonly sessionProviderName: string | null;
158	}): ProviderKind {
159	  if (input.sessionProviderName === "codex") {
160	    return input.sessionProviderName;
161	  }
162	  const normalizedCodex = normalizeModelSlug(input.model, "codex");
163	  if (normalizedCodex && CODEX_MODEL_SLUGS.has(normalizedCodex)) {
164	    return "codex";
165	  }
166	  return "codex";
167	}
