### Part 3: Extending `apps/web/src/hooks/useTheme.ts`

**Strategy**: Extend the existing module-scoped external store, not replace it. Add a second localStorage key for the named theme selection. The existing `theme` ("light" | "dark" | "system") becomes the "mode" while the new `themeId` ("t3-dark" | "t3-light" | "t3-midnight") identifies which named palette is active.

**New storage key**: `"t3code:named-theme"` (following the `t3code:` prefix convention seen in `STORAGE_KEY = "t3code:theme"`, `t3code:app-settings:v1`, etc.)

**Changes to the module**:

1. Import from the shared package: `import { getTheme, listThemes, getDefaultThemeId, type ThemeDefinition } from "@t3tools/shared/themes";`

2. Add a new constant: `const NAMED_THEME_STORAGE_KEY = "t3code:named-theme";`

3. Add a helper to read the stored named theme:
```typescript
function getStoredNamedThemeId(): string {
  const raw = localStorage.getItem(NAMED_THEME_STORAGE_KEY);
  if (raw && getTheme(raw)) return raw;
  return getDefaultThemeId("dark"); // fallback to t3-dark
}
```

4. Extend `ThemeSnapshot` to include `namedThemeId: string`.

5. Add a CSS variable application function:
```typescript
const CSS_VAR_MAP: Record<string, string> = {
  background: "--background",
  foreground: "--foreground",
  card: "--card",
  cardForeground: "--card-foreground",
  // ... all 25 mappings
};

function applyNamedTheme(themeId: string, mode: Theme) {
  const theme = getTheme(themeId);
  if (!theme) return;

  // Determine if this is the default theme for its variant
  const isDefault = themeId === getDefaultThemeId(theme.variant);

  const root = document.documentElement;

  if (isDefault) {
    // Clear all runtime overrides so stylesheet defaults take effect
    for (const cssVar of Object.values(CSS_VAR_MAP)) {
      root.style.removeProperty(cssVar);
    }
  } else {
    // Apply color overrides
    for (const [key, cssVar] of Object.entries(CSS_VAR_MAP)) {
      const value = theme.colors[key as keyof ThemeColors];
      if (value) {
        root.style.setProperty(cssVar, value);
      }
    }
  }
}
```

6. Modify `applyTheme` to also call `applyNamedTheme`:
```typescript
function applyTheme(theme: Theme, suppressTransitions = false) {
  const namedThemeId = getStoredNamedThemeId();
  const namedTheme = getTheme(namedThemeId);

  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Use the named theme's variant to determine dark/light class,
  // BUT respect "system" mode if the named theme variant matches
  const isDark = namedTheme
    ? namedTheme.variant === "dark"
    : theme === "dark" || (theme === "system" && getSystemDark());

  document.documentElement.classList.toggle("dark", isDark);
  applyNamedTheme(namedThemeId, theme);

  if (suppressTransitions) {
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}
```

**Important backward-compatibility consideration**: When no named theme is stored (fresh users, or users with existing `t3code:theme` data), `getStoredNamedThemeId()` returns the default. Since `t3-dark` and `t3-light` are no-ops on CSS variables (they match the stylesheet defaults), the behavior is 100% identical to today. The `.dark` class toggle continues to work exactly as before.

7. Extend the hook's return value:
```typescript
export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const theme = snapshot.theme;
  const namedThemeId = snapshot.namedThemeId;
  const namedTheme = getTheme(namedThemeId);

  const resolvedTheme: "light" | "dark" = namedTheme
    ? namedTheme.variant
    : theme === "system"
      ? snapshot.systemDark ? "dark" : "light"
      : theme;

  const setTheme = useCallback((next: Theme) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  const setNamedTheme = useCallback((id: string) => {
    const t = getTheme(id);
    if (!t) return;
    localStorage.setItem(NAMED_THEME_STORAGE_KEY, id);
    // Also update the mode to match the theme's variant
    const modeValue: Theme = t.variant;
    localStorage.setItem(STORAGE_KEY, modeValue);
    applyTheme(modeValue, true);
    emitChange();
  }, []);

  const availableThemes = listThemes();

  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return {
    theme,
    setTheme,
    resolvedTheme,
    namedThemeId,
    namedTheme: namedTheme ?? null,
    setNamedTheme,
    availableThemes,
  } as const;
}
```

