import { describe, expect, it } from "vitest";

import { getDefaultThemeId, getTheme, listThemes, type ThemeColors } from "./themes";

const EXPECTED_COLOR_KEYS: readonly (keyof ThemeColors)[] = [
  "background",
  "foreground",
  "card",
  "cardForeground",
  "popover",
  "popoverForeground",
  "primary",
  "primaryForeground",
  "secondary",
  "secondaryForeground",
  "muted",
  "mutedForeground",
  "accent",
  "accentForeground",
  "destructive",
  "destructiveForeground",
  "border",
  "input",
  "ring",
  "sidebar",
  "editor",
  "terminal",
  "statusBar",
];

describe("listThemes", () => {
  it("returns exactly 3 built-in themes", () => {
    expect(listThemes()).toHaveLength(3);
  });

  it("returns themes with unique ids", () => {
    const ids = listThemes().map((t) => t.id);
    expect(new Set(ids).size).toBe(ids.length);
  });

  it("every theme has a valid variant", () => {
    for (const theme of listThemes()) {
      expect(["light", "dark"]).toContain(theme.variant);
    }
  });

  it("every theme has all required color keys", () => {
    for (const theme of listThemes()) {
      for (const key of EXPECTED_COLOR_KEYS) {
        expect(theme.colors).toHaveProperty(key);
        expect(typeof theme.colors[key]).toBe("string");
      }
    }
  });

  it("every theme has a fontFamily and fontSize", () => {
    for (const theme of listThemes()) {
      expect(typeof theme.fontFamily).toBe("string");
      expect(theme.fontFamily.length).toBeGreaterThan(0);
      expect(typeof theme.fontSize).toBe("number");
      expect(theme.fontSize).toBeGreaterThan(0);
    }
  });

  it("every theme has previewColors with hex values", () => {
    for (const theme of listThemes()) {
      expect(typeof theme.previewColors.background).toBe("string");
      expect(typeof theme.previewColors.foreground).toBe("string");
      expect(typeof theme.previewColors.primary).toBe("string");
      expect(typeof theme.previewColors.accent).toBe("string");
    }
  });
});

describe("getTheme", () => {
  it("returns t3-dark", () => {
    const theme = getTheme("t3-dark");
    expect(theme).toBeDefined();
    expect(theme!.id).toBe("t3-dark");
    expect(theme!.name).toBe("T3 Dark");
    expect(theme!.variant).toBe("dark");
  });

  it("returns t3-light", () => {
    const theme = getTheme("t3-light");
    expect(theme).toBeDefined();
    expect(theme!.id).toBe("t3-light");
    expect(theme!.name).toBe("T3 Light");
    expect(theme!.variant).toBe("light");
  });

  it("returns t3-midnight", () => {
    const theme = getTheme("t3-midnight");
    expect(theme).toBeDefined();
    expect(theme!.id).toBe("t3-midnight");
    expect(theme!.name).toBe("T3 Midnight");
    expect(theme!.variant).toBe("dark");
  });

  it("returns undefined for unknown id", () => {
    expect(getTheme("nonexistent")).toBeUndefined();
  });

  it("returns undefined for empty string", () => {
    expect(getTheme("")).toBeUndefined();
  });
});

describe("getDefaultThemeId", () => {
  it("returns t3-dark for dark variant", () => {
    expect(getDefaultThemeId("dark")).toBe("t3-dark");
  });

  it("returns t3-light for light variant", () => {
    expect(getDefaultThemeId("light")).toBe("t3-light");
  });

  it("returned ids resolve via getTheme", () => {
    expect(getTheme(getDefaultThemeId("dark"))).toBeDefined();
    expect(getTheme(getDefaultThemeId("light"))).toBeDefined();
  });
});

