import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  getDefaultThemeId,
  getTheme,
  listThemes,
  type ThemeColors,
  type ThemeDefinition,
} from "@t3tools/shared/themes";

type Theme = "light" | "dark" | "system";
type ThemeSnapshot = {
  theme: Theme;
  systemDark: boolean;
  namedThemeId: string;
};

const STORAGE_KEY = "t3code:theme";
const NAMED_THEME_STORAGE_KEY = "t3code:named-theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

// ---------------------------------------------------------------------------
// CSS custom property mapping
// ---------------------------------------------------------------------------

/**
 * Maps camelCase `ThemeColors` keys to their CSS custom property names.
 * Only keys that have a matching variable defined in `index.css` are included —
 * `sidebar`, `editor`, `terminal`, and `statusBar` are omitted because no
 * component references those variables yet.
 */
const COLOR_TO_CSS_VAR: ReadonlyArray<readonly [keyof ThemeColors, string]> = [
  ["background", "--background"],
  ["foreground", "--foreground"],
  ["card", "--card"],
  ["cardForeground", "--card-foreground"],
  ["popover", "--popover"],
  ["popoverForeground", "--popover-foreground"],
  ["primary", "--primary"],
  ["primaryForeground", "--primary-foreground"],
  ["secondary", "--secondary"],
  ["secondaryForeground", "--secondary-foreground"],
  ["muted", "--muted"],
  ["mutedForeground", "--muted-foreground"],
  ["accent", "--accent"],
  ["accentForeground", "--accent-foreground"],
  ["destructive", "--destructive"],
  ["destructiveForeground", "--destructive-foreground"],
  ["border", "--border"],
  ["input", "--input"],
  ["ring", "--ring"],
];

// ---------------------------------------------------------------------------
// Module-level store (runs outside React)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStored(): Theme {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function getStoredNamedThemeId(): string {
  const raw = localStorage.getItem(NAMED_THEME_STORAGE_KEY);
  if (raw && getTheme(raw)) return raw;
  return getDefaultThemeId("dark");
}

// ---------------------------------------------------------------------------
// Theme application
// ---------------------------------------------------------------------------

/**
 * Apply (or clear) inline CSS variable overrides for the named theme.
 *
