function applyNamedTheme(themeId: string) {
  const theme = getTheme(themeId);
  const root = document.documentElement;

  if (!theme) {
    // Unknown theme — clear all overrides
    for (const [, cssVar] of COLOR_TO_CSS_VAR) {
      root.style.removeProperty(cssVar);
    }
    return;
  }

  for (const [colorKey, cssVar] of COLOR_TO_CSS_VAR) {
    const value = theme.colors[colorKey];
    if (value) {
      root.style.setProperty(cssVar, value);
    } else {
      root.style.removeProperty(cssVar);
