import type { ThemeDefinition } from "@t3tools/shared/themes";

import { useTheme } from "../hooks/useTheme";

function ThemeSwatch({ color, label }: { color: string; label: string }) {
  return (
    <span
      className="size-4 rounded-full border border-border/60"
      style={{ backgroundColor: color }}
      aria-label={label}
    />
  );
}

function ThemeOption({
  theme,
  selected,
  onSelect,
}: {
  theme: ThemeDefinition;
  selected: boolean;
  onSelect: () => void;
}) {
  const { previewColors } = theme;
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      className={`flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors ${
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent"
      }`}
      onClick={onSelect}
    >
      <span className="flex flex-col gap-1.5">
        <span className="flex items-center gap-2">
          <span className="text-sm font-medium">{theme.name}</span>
          <span className="text-[10px] text-muted-foreground">{theme.variant}</span>
        </span>
        <span className="flex gap-1.5" aria-label={`${theme.name} color preview`}>
          <ThemeSwatch color={previewColors.background} label="background" />
          <ThemeSwatch color={previewColors.primary} label="primary" />
          <ThemeSwatch color={previewColors.accent} label="accent" />
          <ThemeSwatch color={previewColors.foreground} label="foreground" />
        </span>
      </span>
      {selected ? (
        <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Selected
        </span>
      ) : null}
    </button>
  );
}

export function ThemeSelector() {
  const { namedThemeId, setNamedTheme, availableThemes, resolvedTheme } = useTheme();

  return (
    <div>
      <div className="space-y-2" role="radiogroup" aria-label="Color theme">
        {availableThemes.map((theme) => (
          <ThemeOption
            key={theme.id}
            theme={theme}
            selected={namedThemeId === theme.id}
            onSelect={() => setNamedTheme(theme.id)}
          />
        ))}
      </div>

      <p className="mt-4 text-xs text-muted-foreground">
        Active theme: <span className="font-medium text-foreground">{resolvedTheme}</span>
      </p>
    </div>
  );
}

